namespace BgControls.Windows.Controls;/// <summary>/// 定义窗口互操作性适配器的接口./// </summary>public interface IWindowInteropabilityAdapter{    /// <summary>    /// Gets 窗口句柄.    /// </summary>    IntPtr Handle { get; }    /// <summary>    /// Gets 窗口相对于屏幕左侧的绝对位置.    /// </summary>    int AbsoluteLeft { get; }    /// <summary>    /// Gets 窗口相对于屏幕顶部的绝对位置.    /// </summary>    int AbsoluteTop { get; }}